// HasLionPolicies applies the HasEdge predicate on the "lion_policies" edge.
func HasLionPolicies() predicate.PolicyAttachments {
	return predicate.PolicyAttachments(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, LionPoliciesTable, LionPoliciesColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasLionPoliciesWith applies the HasEdge predicate on the "lion_policies" edge with a given conditions (other predicates).
func HasLionPoliciesWith(preds ...predicate.Policies) predicate.PolicyAttachments {
	return predicate.PolicyAttachments(func(s *sql.Selector) {
		step := newLionPoliciesStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.PolicyAttachments) predicate.PolicyAttachments {
	return predicate.PolicyAttachments(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.PolicyAttachments) predicate.PolicyAttachments {
	return predicate.PolicyAttachments(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.PolicyAttachments) predicate.PolicyAttachments {
	return predicate.PolicyAttachments(sql.NotPredicates(p))
}
